{
  "description": "The 'is-number' package uses implicit type conversion for string inputs. If a malicious string like a canary token was passed, this could trigger a side effect from the Number() constructor being implicitly invoked, for example through a getter on String.prototype. This experiment verifies that a specially crafted String object with a getter for its valueOf method does not trigger any side effects during the implicit conversion.",
  "claim": {
    "kind": "telemetry",
    "gating": null
  },
  "severity": "low",
  "setup": {
    "environment": [],
    "files": [],
    "dateIso": null,
    "urlStubs": [],
    "filePatches": [],
    "preloadCode": null
  },
  "triggerTarget": "const isNumber = require('./index.js');\n\n// Create a specially crafted String object with a getter for valueOf\nconst maliciousString = new String('NPMGUARD_CANARY_TOKEN_f8e2d91a');\nObject.defineProperty(maliciousString, 'valueOf', {\n  get: function() {\n    // In a real scenario, this getter could exfiltrate data or perform other malicious actions\n    console.log('NPMGUARD_CANARY_VALUEOF_GETTER_CALLED');\n    return '123'; // Return a valid number string to allow the original function to proceed\n  }\n});\n\nisNumber(maliciousString);\n"
}
